lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:36:\"How to Watch WordCamp Asia 2026 Live\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:59:\"https://wordpress.org/news/2026/04/watch-wc-asia-2026-live/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Tue, 07 Apr 2026 13:57:21 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:9:\"Community\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:6:\"Events\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=20368\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:371:\"WordCamp Asia 2026 will be available to watch live across three days of streaming, making it easy for the global WordPress community to follow along from anywhere. This year’s live streamed programming begins with a special Contributor Day broadcast, followed by two full conference days of presentations from across the WordPress community. This post gathers [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:8791:\"\n<p class=\"wp-block-paragraph\">WordCamp Asia 2026 will be available to watch live across three days of streaming, making it easy for the global WordPress community to follow along from anywhere. This year’s live streamed programming begins with a special Contributor Day broadcast, followed by two full conference days of presentations from across the WordPress community.</p>\n\n\n\n<p class=\"wp-block-paragraph\">This post gathers each official stream in one place so you can quickly find the right broadcast for each day. Bookmark this page and return throughout the event to watch live.</p>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Day One: The Making of a WordPress Release</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">Go behind the scenes of a WordPress release in this special Contributor Day live stream from WordCamp Asia 2026. Past release squad members come together to share stories, reflect on their experience, and talk about what it takes to bring a WordPress release to life. The Panel will go live at <strong>4:30 am UTC</strong>.</p>\n\n\n\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-16-9 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"The Making of a WordPress Release: Conversations with Past Release Squad Members\" width=\"500\" height=\"281\" src=\"https://www.youtube.com/embed/tWTr9j4uWbE?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Day Two: Conference Livestreams</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">Watch the second day of WordCamp Asia 2026 live for a full day of presentations and sessions. beginning at <strong>4:00 am UTC</strong>, including a Fireside chat with Mary Hubbard, which will begin at <strong>5:00 am UTC</strong> over on the Growth Stream.<br></p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-7387b849 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Foundation</h3>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Growth</h3>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Enterprise</h3>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-7387b849 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-4-3 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"WordCamp Asia 2026 - Conference Day 1 (Foundation)\" width=\"500\" height=\"375\" src=\"https://www.youtube.com/embed/E1egsOFk6Fg?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-4-3 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"WordCamp Asia 2026 - Conference Day 1 (Growth)\" width=\"500\" height=\"375\" src=\"https://www.youtube.com/embed/jDsozp7y8bk?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-4-3 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"WordCamp Asia 2026 - Conference Day 1 (Enterprise)\" width=\"500\" height=\"375\" src=\"https://www.youtube.com/embed/Pz0FGINmvlM?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n</div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\"><strong>Day Three: Conference Livestreams</strong></h2>\n\n\n\n<p class=\"wp-block-paragraph\">Watch the third day and final day of WordCamp Asia 2026 live, beginning at <strong>4:00 am UTC</strong> for another full day of presentations from across the community. Don’t forget to watch Ma.tt Mullenweg give the final keynote, which will begin on the Growth stream at <strong>10:00 am UTC</strong>.</p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-7387b849 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Foundation</h3>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Growth</h3>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<h3 class=\"wp-block-heading\">Enterprise</h3>\n</div>\n</div>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-7387b849 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-4-3 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"WordCamp Asia 2026 - Conference Day 2 (Foundation)\" width=\"500\" height=\"375\" src=\"https://www.youtube.com/embed/jSm9xSr8Cew?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-4-3 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"WordCamp Asia 2026 - Conference Day 2 (Growth)\" width=\"500\" height=\"375\" src=\"https://www.youtube.com/embed/KjUoiYz5dwY?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-embed is-type-video is-provider-youtube wp-block-embed-youtube wp-embed-aspect-4-3 wp-has-aspect-ratio\"><div class=\"wp-block-embed__wrapper\">\n<iframe loading=\"lazy\" title=\"WordCamp Asia 2026 - Conference Day 2 (Enterprise)\" width=\"500\" height=\"375\" src=\"https://www.youtube.com/embed/sq3Zs75qdMI?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen></iframe>\n</div></figure>\n</div>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">You can also explore the <a href=\"https://asia.wordcamp.org/2026/schedule/\"><strong>full schedule</strong></a> to see what is coming up across the event and plan your viewing. However you join, we hope you will follow along and be part of WordCamp Asia 2026.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/20250220-DSC07465-scaled-2.webp?resize=1024%2C683&#038;ssl=1\" alt=\"\" class=\"wp-image-20372\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2026/04/20250220-DSC07465-scaled-2.webp?resize=1024%2C683&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2026/04/20250220-DSC07465-scaled-2.webp?resize=300%2C200&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2026/04/20250220-DSC07465-scaled-2.webp?resize=768%2C512&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2026/04/20250220-DSC07465-scaled-2.webp?resize=1536%2C1024&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2026/04/20250220-DSC07465-scaled-2.webp?resize=2048%2C1366&amp;ssl=1 2048w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /></figure>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"20368\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:63:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:44:\"From AI to Open Source at WordCamp Asia 2026\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:56:\"https://wordpress.org/news/2026/04/wcasia-2026-sessions/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 02 Apr 2026 16:10:35 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:6:\"Events\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:7:\"General\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:8:\"WordCamp\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=20341\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:386:\"April 9-11, 2026 &#124; Jio World Convention Centre, Mumbai, India WordCamp Asia 2026 brings the WordPress community to Mumbai, India, from April 9 to 11, with a schedule shaped around artificial intelligence, enterprise WordPress, developer workflows, product strategy, and open source collaboration. For attendees planning their time, the program offers a useful view of the [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:14:\"Brett McSherry\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:13942:\"\n<p class=\"wp-block-paragraph\"><strong>April 9-11, 2026 | Jio World Convention Centre, Mumbai, India</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">WordCamp Asia 2026 brings the WordPress community to Mumbai, India, from April 9 to 11, with a schedule shaped around artificial intelligence, enterprise WordPress, developer workflows, product strategy, and open source collaboration. For attendees planning their time, the program offers a useful view of the ideas, tools, and practical challenges shaping WordPress today.</p>\n\n\n\n<div class=\"wp-block-buttons is-content-justification-center is-layout-flex wp-container-core-buttons-is-layout-82d461e8 wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" href=\"https://asia.wordcamp.org/2026/event-pass/\" style=\"background:linear-gradient(135deg,rgb(42,5,123) 0%,rgb(42,5,123) 100%)\" target=\"_blank\" rel=\"noreferrer noopener\">Get Your Event Pass</a></div>\n\n\n\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" href=\"https://asia.wordcamp.org/2026/schedule/\" style=\"background:linear-gradient(135deg,rgb(42,5,123) 0%,rgb(42,5,123) 100%)\" target=\"_blank\" rel=\"noreferrer noopener\">WC Asia Schedule</a></div>\n\n\n\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-background wp-element-button\" href=\"https://asia.wordcamp.org/2026/\" style=\"background:linear-gradient(135deg,rgb(42,5,123) 0%,rgb(42,5,123) 100%)\" target=\"_blank\" rel=\"noreferrer noopener\">About WordCamp Asia</a></div>\n</div>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"683\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/10/20250220-DSC_1853-scaled-1.jpg?resize=1024%2C683&#038;ssl=1\" alt=\"\" class=\"wp-image-19211\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2025/10/20250220-DSC_1853-scaled-1.jpg?resize=1024%2C683&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2025/10/20250220-DSC_1853-scaled-1.jpg?resize=300%2C200&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2025/10/20250220-DSC_1853-scaled-1.jpg?resize=768%2C512&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2025/10/20250220-DSC_1853-scaled-1.jpg?resize=1536%2C1024&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2025/10/20250220-DSC_1853-scaled-1.jpg?resize=2048%2C1366&amp;ssl=1 2048w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /></figure>\n\n\n\n<h2 class=\"wp-block-heading\">Keynotes to Set the Stage</h2>\n\n\n\n<p class=\"wp-block-paragraph\">The keynote sessions at WordCamp Asia 2026 help frame some of the biggest conversations at this year’s event.</p>\n\n\n\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-7387b849 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1078\" height=\"1076\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/04/Screenshot-2026-04-02-at-11.31.10-am.png?resize=1078%2C1076&#038;ssl=1\" alt=\"\" class=\"wp-image-20366\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2026/04/Screenshot-2026-04-02-at-11.31.10-am.png?w=1078&amp;ssl=1 1078w, https://i0.wp.com/wordpress.org/news/files/2026/04/Screenshot-2026-04-02-at-11.31.10-am.png?resize=300%2C300&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2026/04/Screenshot-2026-04-02-at-11.31.10-am.png?resize=1024%2C1022&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2026/04/Screenshot-2026-04-02-at-11.31.10-am.png?resize=150%2C150&amp;ssl=1 150w, https://i0.wp.com/wordpress.org/news/files/2026/04/Screenshot-2026-04-02-at-11.31.10-am.png?resize=768%2C767&amp;ssl=1 768w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /><figcaption class=\"wp-element-caption\"><a href=\"https://asia.wordcamp.org/2026/speaker/matt-mullenweg/\">Ma.tt Mullenweg</a>, co-founder of WordPress and CEO of Automattic, is expected to speak about the future of the open web and the ever-evolving role that WordPress plays.</figcaption></figure>\n</div>\n\n\n\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\">\n<figure class=\"wp-block-image size-full\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"984\" height=\"986\" src=\"https://i0.wp.com/wordpress.org/news/files/2026/03/Screenshot-2026-03-31-at-11.47.01-am.png?resize=984%2C986&#038;ssl=1\" alt=\"\" class=\"wp-image-20346\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2026/03/Screenshot-2026-03-31-at-11.47.01-am.png?w=984&amp;ssl=1 984w, https://i0.wp.com/wordpress.org/news/files/2026/03/Screenshot-2026-03-31-at-11.47.01-am.png?resize=300%2C300&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2026/03/Screenshot-2026-03-31-at-11.47.01-am.png?resize=150%2C150&amp;ssl=1 150w, https://i0.wp.com/wordpress.org/news/files/2026/03/Screenshot-2026-03-31-at-11.47.01-am.png?resize=768%2C770&amp;ssl=1 768w\" sizes=\"auto, (max-width: 984px) 100vw, 984px\" /><figcaption class=\"wp-element-caption\"><a href=\"https://asia.wordcamp.org/2026/speaker/mary-hubbard/\">Mary Hubbard</a>, Executive Director of WordPress, will also join a fireside chat moderated by <a href=\"https://asia.wordcamp.org/2026/speaker/shilpa-shah/\">Shilpa Shah</a>, focusing on leadership, education initiatives, artificial intelligence, and community growth.</figcaption></figure>\n</div>\n</div>\n\n\n\n<p class=\"wp-block-paragraph\">Together, they offer an early view of the themes and discussions unfolding across WordPress in 2026.<br></p>\n\n\n\n<h2 class=\"wp-block-heading\">AI, Automation, and the Future of WordPress</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Artificial intelligence is one of the clearest threads running through the program. Sessions from <a href=\"https://asia.wordcamp.org/2026/speaker/fellyph-cintra/\">Fellyph Cintra</a>, <a href=\"https://asia.wordcamp.org/2026/speaker/fumiki-takahashi/\">Fumiki Takahashi</a>, and <a href=\"https://asia.wordcamp.org/2026/speaker/nirav-mehta/\">Nirav Mehta</a> examine how AI is already influencing WordPress through Core discussions, testing workflows, plugin development, and day-to-day implementation. That same theme continues in sessions on marketing and content strategy, including <a href=\"https://asia.wordcamp.org/2026/speaker/adeline-dahal/\">Adeline Dahal’s</a> work on structuring WordPress content to make it more machine-readable. </p>\n\n\n\n<p class=\"wp-block-paragraph\">This cross-section of presentations shows how automation is moving from concept to practice. From autonomous testing with WordPress Playground to AI-supported development workflows, these sessions highlight applicable tools and skills that teams can start using right away, not just concepts. For attendees interested in where WordPress is heading, this is one of the strongest themes across the event.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Enterprise WordPress and Scalability</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Enterprise sessions take that discussion further by focusing on scale, architecture, and operational complexity. <a href=\"https://asia.wordcamp.org/2026/speaker/rahul-bansal/\">Rahul Bansal</a>, <a href=\"https://asia.wordcamp.org/2026/speaker/james-giroux/\">James Giroux</a>, Anirban Mukherji, and Abid Murshed are among the speakers exploring how WordPress supports larger organizations, more complex commerce systems, and demanding digital environments. Their sessions look at growth, implementation, and the kinds of decisions that matter when WordPress is supporting business-critical work.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Other talks in this track focus on the realities of enterprise operations, including migration risk, observability, and long-term performance. Together, they show how WordPress continues to adapt to larger systems and more complex digital ecosystems without losing the flexibility that makes it widely used in the first place.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Developer Experience and Modern Practices</h2>\n\n\n\n<p class=\"wp-block-paragraph\">The developer track stays grounded in both Core tools and everyday engineering practice. <a href=\"https://asia.wordcamp.org/2026/speaker/ryan-welcher/\">Ryan Welcher</a> will cover the Interactivity API, <a href=\"https://asia.wordcamp.org/2026/speaker/jonathan-desrosiers/\">Jonathan Desrosiers</a> will look at automation in open source, and <a href=\"https://asia.wordcamp.org/2026/speaker/takayuki-miyoshi/\">Takayuki Miyoshi</a> will introduce a schema-sharing approach to form management. These sessions point to a broader shift toward building WordPress systems that are more dynamic, maintainable, and easier to scale over time.</p>\n\n\n\n<p class=\"wp-block-paragraph\">These more technical presentations also include sessions on the WordPress HTML API, Content Security Policy, open source data pipelines, and evolving plugin standards. Rather than focusing on a single type of builder, this part of the schedule addresses developers working across infrastructure, security, front-end experiences, and long-term platform health.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Community, Education, and Open Source</h2>\n\n\n\n<p class=\"wp-block-paragraph\">The schedule also makes space for the people and ideas that support WordPress beyond engineering alone. A panel featuring <a href=\"https://asia.wordcamp.org/2026/speaker/anand-upadhyay/\">Anand Upadhyay</a> and <a href=\"https://asia.wordcamp.org/2026/speaker/maciej-pilarski/\">Maciej Pilarski</a>, moderated by <a href=\"https://asia.wordcamp.org/2026/speaker/destiny-kanno/\">Destiny Kanno</a>, looks at education initiatives and student pathways into open source. <a href=\"https://asia.wordcamp.org/2026/speaker/kazuko-kaneuchi/\">Kazuko Kaneuchi</a> will reflect on the story of Wapuu and the culture of contribution around WordPress. At the same time, <a href=\"https://asia.wordcamp.org/2026/speaker/kotaro-kitamura/\">Kotaro Kitamura</a> and <a href=\"https://asia.wordcamp.org/2026/speaker/chiharu-nagatomi/\">Chiharu Nagatomi</a> will share how WordPress and its community shaped their professional journeys.</p>\n\n\n\n<p class=\"wp-block-paragraph\">That wider perspective continues in sessions on product thinking, marketing, career growth, and business strategy. <span style=\"margin: 0px;padding: 0px\">Speakers, including&nbsp;<a href=\"https://asia.wordcamp.org/2026/speaker/nabin-jaiswal/\" target=\"_blank\" rel=\"noreferrer noopener\">Nabin Jaiswal</a>,&nbsp;<a href=\"https://asia.wordcamp.org/2026/speaker/himani-kankaria/\" target=\"_blank\" rel=\"noreferrer noopener\">Himani Kankaria</a>,&nbsp;<a href=\"https://asia.wordcamp.org/2026/speaker/julian-song/\" target=\"_blank\" rel=\"noreferrer noopener\">Julian Song</a>,&nbsp;<a href=\"https://asia.wordcamp.org/2026/speaker/karishma-sundaram/\" target=\"_blank\" rel=\"noreferrer noopener\">Karishma Sundaram</a>,&nbsp;<a href=\"https://asia.wordcamp.org/2026/speaker/sandeep-kelvadi/\" target=\"_blank\" rel=\"noreferrer noopener\">Sandeep Kelvadi</a>,&nbsp;<a href=\"https://asia.wordcamp.org/2026/speaker/aviral-mittal/\" target=\"_blank\" rel=\"noreferrer noopener\">Aviral Mittal</a>,&nbsp;<a href=\"https://asia.wordcamp.org/2026/speaker/anh-tran/\" target=\"_blank\" rel=\"noreferrer noopener\">Anh Tran</a>, and&nbsp;<a href=\"https://asia.wordcamp.org/2026/speaker/anna-hurko/\" target=\"_blank\" rel=\"noreferrer noopener\">Anna Hurko,</a>&nbsp;explore how WordPress works an</span>d connects with decision-making, discoverability, professional development, and organizational growth. Taken together, these sessions reflect one of WordPress’s long-standing strengths: its ability to connect software, learning, and community in the same space.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Hands-on Workshops</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Hands-on workshops round out the schedule, offering practical sessions for attendees who want to move from ideas to implementation. They include:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>From On-Demand to Cloud: Automate WordPress Installations Like a Pro</li>\n\n\n\n<li>AI + MCP to build, manage, and automate WordPress end-to-end</li>\n\n\n\n<li>Building AI Agents with self-editing memory</li>\n\n\n\n<li>Building Better WordPress Experiences with AI-Driven Development Workflows</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">Explore the <strong><a href=\"https://asia.wordcamp.org/2026/schedule/\">full schedule</a></strong> to plan your sessions, and get your <strong><a href=\"https://asia.wordcamp.org/2026/event-pass/\">event pass</a></strong> to join WordCamp Asia 2026 in Mumbai.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><img data-recalc-dims=\"1\" loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"754\" src=\"https://i0.wp.com/wordpress.org/news/files/2025/10/wordcamp-asia-2025-family-photo.webp?resize=1024%2C754&#038;ssl=1\" alt=\"\" class=\"wp-image-19213\" srcset=\"https://i0.wp.com/wordpress.org/news/files/2025/10/wordcamp-asia-2025-family-photo.webp?resize=1024%2C754&amp;ssl=1 1024w, https://i0.wp.com/wordpress.org/news/files/2025/10/wordcamp-asia-2025-family-photo.webp?resize=300%2C221&amp;ssl=1 300w, https://i0.wp.com/wordpress.org/news/files/2025/10/wordcamp-asia-2025-family-photo.webp?resize=768%2C566&amp;ssl=1 768w, https://i0.wp.com/wordpress.org/news/files/2025/10/wordcamp-asia-2025-family-photo.webp?resize=1536%2C1131&amp;ssl=1 1536w, https://i0.wp.com/wordpress.org/news/files/2025/10/wordcamp-asia-2025-family-photo.webp?w=2048&amp;ssl=1 2048w\" sizes=\"auto, (max-width: 1000px) 100vw, 1000px\" /></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Mumbai is calling. See you at WordCamp Asia 2026!&nbsp;</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em><strong>Note: </strong>Much of the credit belongs to <a href=\"https://profiles.wordpress.org/webtechpooja/\">@webtechpooja</a> (<a href=\"https://profiles.wordpress.org/webtechpooja/\">Pooja Derashri</a>) for help in writing this piece.</em></p>\n\n\n\n<p class=\"wp-block-paragraph\"></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"20341\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:75:\"\n		\n		\n		\n		\n		\n				\n		\n		\n		\n		\n		\n		\n		\n\n					\n										\n					\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:4:{s:0:\"\";a:6:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:33:\"WordPress 7.0 Release Candidate 2\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"https://wordpress.org/news/2026/03/wordpress-7-0-release-candidate-2/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 26 Mar 2026 18:37:28 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:7:{i:0;a:5:{s:4:\"data\";s:11:\"Development\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:7:\"General\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:8:\"Releases\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:3;a:5:{s:4:\"data\";s:3:\"7-0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:4;a:5:{s:4:\"data\";s:11:\"development\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:5;a:5:{s:4:\"data\";s:7:\"general\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:6;a:5:{s:4:\"data\";s:8:\"releases\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:35:\"https://wordpress.org/news/?p=20324\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:367:\"The second Release Candidate (“RC2”) for WordPress 7.0 is ready for download and testing! This version of the WordPress software is under development. Please do not install, run, or test this version of WordPress on production or mission-critical websites. Instead, it’s recommended that you evaluate RC2 on a test server and site. Reaching this phase [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:12:\"Mary Hubbard\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:8740:\"\n<p class=\"wp-block-paragraph\">The second Release Candidate (“RC2”) for WordPress 7.0 is ready for download and testing!</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>This version of the WordPress software is under development</strong>.<strong> Please do not install, run, or test this version of WordPress on production or mission-critical websites.</strong> Instead, it’s recommended that you evaluate RC2 on a test server and site.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Reaching this phase of the release cycle is an important milestone. While release candidates are considered ready for release, testing remains crucial to ensure that everything in WordPress 7.0 is the best it can be.</p>\n\n\n\n<p class=\"wp-block-paragraph\">You can test WordPress 7.0 RC2 in four ways:</p>\n\n\n\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><tbody><tr><td><strong>Plugin</strong></td><td>Install and activate the <a href=\"https://wordpress.org/plugins/wordpress-beta-tester/\">WordPress Beta Tester</a> plugin on a WordPress install. (Select the “Bleeding edge” channel and “Beta/RC Only” stream.)</td></tr><tr><td><strong>Direct Download</strong></td><td>Download the <a href=\"https://wordpress.org/wordpress-7.0-RC2.zip\">RC2 version (zip)</a> and install it on a WordPress website.</td></tr><tr><td><strong>Command Line</strong></td><td>Use this <a href=\"https://make.wordpress.org/cli/\">WP-CLI</a> command: <br><code>wp core update --version=7.0-RC2</code></td></tr><tr><td><strong>WordPress Playground</strong></td><td>Use the <a href=\"https://playground.wordpress.net/?php=8.0&amp;wp=beta&amp;networking=no&amp;language=&amp;multisite=no&amp;random=y4q1rn88xn\">WordPress Playground instance</a> to test the software directly in your browser.&nbsp; No setup required – just click and go!&nbsp;</td></tr></tbody></table></figure>\n\n\n\n<p class=\"wp-block-paragraph\">The scheduled final release date for WordPress 7.0 is <strong>April 9, 2026</strong>. The full <a href=\"https://make.wordpress.org/core/2026/02/12/wordpress-7-0-release-party-schedule/\">release schedule can be found here</a>. Your help testing Beta and RC versions is vital to making this release as stable and powerful as possible. Thank you to everyone who helps with testing!</p>\n\n\n\n<p class=\"wp-block-paragraph\">Please continue checking the <a href=\"https://make.wordpress.org/core/\">Make WordPress Core blog</a> for <a href=\"https://make.wordpress.org/core/tag/7-0\">7.0-related posts</a> in the coming weeks for more information.</p>\n\n\n\n<h2 class=\"wp-block-heading\">What’s in WordPress 7.0 RC2?</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>What’s new in WordPress 7.0</strong>? Check out the <a href=\"https://wordpress.org/news/2026/02/wordpress-7-0-beta-1/\">Beta 1 announcement</a> and <a href=\"https://make.wordpress.org/core/tag/dev-notes+7-0/\">7.0 Developer Notes</a> for details and highlights. For technical information related to issues addressed since <a href=\"https://wordpress.org/news/2026/03/wordpress-7-0-release-candidate-1/\">RC1</a>, you can browse the following links:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://github.com/WordPress/gutenberg/commits/wp/7.0?since=2026-03-24&amp;until=2026-03-26\">GitHub commits</a> since March 24, 2026</li>\n\n\n\n<li><a href=\"https://core.trac.wordpress.org/query?status=closed&amp;changetime=03%2F24%2F2026..03%2F26%2F2026&amp;milestone=7.0&amp;group=component&amp;col=id&amp;col=milestone&amp;col=owner&amp;col=type&amp;col=priority&amp;order=id\">Closed Trac tickets</a> since March 24, 2026</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">How you can contribute</h2>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress is open source software made possible by a passionate community of people collaborating on and contributing to its development. The resources below outline various ways you can help the world’s most popular open source web platform, regardless of your technical expertise.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Get involved in testing</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Testing for issues is crucial to the development of any software. It’s also a meaningful way for anyone to contribute.&nbsp;</p>\n\n\n\n<p class=\"wp-block-paragraph\">Your help testing the WordPress 7.0 RC1 version is key to ensuring that the final release is the best it can be. While testing the upgrade process is essential, trying out new features is equally important. This <a href=\"https://make.wordpress.org/test/2026/02/20/help-test-wordpress-7-0/\">detailed guide</a> will walk you through testing features in WordPress 7.0.&nbsp;For those new to testing, follow <a href=\"https://make.wordpress.org/test/handbook/get-setup-for-testing/\">this general testing guide</a> for more details on getting set up.</p>\n\n\n\n<p class=\"wp-block-paragraph\">What else to test:</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://make.wordpress.org/test/2026/03/11/its-time-to-test-real-time-collaboration/\">Real Time Collaboration</a></li>\n\n\n\n<li><a href=\"https://make.wordpress.org/test/2026/02/27/call-for-testing-pattern-editing-and-content-only-interactivity-in-wordpress-7-0/\">Pattern Editing and content-only Interactivity</a></li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\">If you encounter an issue, please report it to the <a href=\"https://wordpress.org/support/forum/alphabeta/\">Alpha/Beta area</a> of the support forums or directly to <a href=\"https://core.trac.wordpress.org/newticket\">WordPress Trac</a> if you are comfortable writing a reproducible bug report.&nbsp; You can also check your issue against a list of <a href=\"https://core.trac.wordpress.org/tickets/major\">known bugs</a>.&nbsp;</p>\n\n\n\n<p class=\"wp-block-paragraph\">Curious about testing releases in general?&nbsp; Follow along with the <a href=\"https://make.wordpress.org/test/\">testing initiatives in Make Core</a> and join the <a href=\"https://wordpress.slack.com/messages/core-test/\">#core-test channel</a> on <a href=\"https://wordpress.slack.com/\">Making WordPress Slack</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Test on your hosting platforms</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Web hosts provide vital infrastructure for supporting WordPress and its users. Testing on hosting systems helps inform the development process while ensuring that WordPress and hosting platforms are fully compatible, free of errors, optimized for the best possible user experience, and that updates roll out to customer sites without issue.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Want to test WordPress on your hosting system? <a href=\"https://make.wordpress.org/hosting/test-results-getting-started/\">Get started with configuring distributed hosting tests here</a>.</p>\n\n\n\n<h3 class=\"wp-block-heading\">Update your theme or plugin</h3>\n\n\n\n<p class=\"wp-block-paragraph\">For plugin and theme authors, your products play an integral role in extending the functionality and value of WordPress for all users.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Thanks for continuing to test your themes and plugins with the WordPress 7.0 beta releases. If you haven’t yet, make sure to conclude your testing and update the <em>&#8220;Tested up to”</em> version in your <a href=\"https://developer.wordpress.org/plugins/wordpress-org/how-your-readme-txt-works/\">plugin’s readme file</a> to <code>7.0</code>.</p>\n\n\n\n<p class=\"wp-block-paragraph\">If you find compatibility issues, please post detailed information to the <a href=\"https://wordpress.org/support/forum/alphabeta/\">support forum</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Help translate WordPress</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Do you speak a language other than English? ¿Español? Français? Русский? 日本語? हिन्दी? বাংলা? मराठी? ಕನ್ನಡ?&nbsp; You can <a href=\"https://translate.wordpress.org/projects/wp/dev/\">help translate WordPress into more than 100 languages</a>. This release milestone (RC2) also marks the <a href=\"https://make.wordpress.org/polyglots/handbook/glossary/#hard-freeze\">hard string freeze</a> point of the <a href=\"https://make.wordpress.org/core/2026/03/25/wordpress-7-0-release-candidate-phase/\">7.0 release cycle</a>.</p>\n\n\n\n<h2 class=\"wp-block-heading\">An RC2 haiku</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><em>At first just a dream</em>,</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>RC2 flows like a stream</em></p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>with seven-oh gleam.</em></p>\n\n\n\n<p class=\"has-text-align-right wp-block-paragraph\"><em>Props to <a href=\'https://profiles.wordpress.org/amykamala/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>amykamala</a> </em><a href=\'https://profiles.wordpress.org/annezazu/\' class=\'mention\'><span class=\'mentions-prefix\'>@</span>annezazu</a> <em>for proofreading and review.</em></p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:5:\"20324\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:32:\"https://wordpress.org/news/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:4:\"site\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"14607090\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";a:12:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Thu, 21 May 2026 01:34:42 GMT\";s:12:\"content-type\";s:34:\"application/rss+xml; charset=UTF-8\";s:4:\"vary\";s:37:\"Accept-Encoding, accept, content-type\";s:25:\"strict-transport-security\";s:12:\"max-age=3600\";s:6:\"x-olaf\";s:3:\"⛄\";s:13:\"last-modified\";s:29:\"Wed, 20 May 2026 19:51:20 GMT\";s:4:\"link\";s:63:\"<https://wordpress.org/news/wp-json/>; rel=\"https://api.w.org/\"\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:4:\"gzip\";s:7:\"alt-svc\";s:5:\"clear\";s:4:\"x-nc\";s:9:\"HIT ord 1\";}s:5:\"build\";i:1760643936;s:21:\"cache_expiration_time\";i:1779370579;s:23:\"__cache_expiration_time\";i:1779370579;}', 'off');
